  let current = node;
  while (current.children.length > 0) {
    // Follow the most visited child (robust child selection)
    current = current.children.reduce((best, child) =>
      child.visits > best.visits ? child : best
    );
    if (!current) break;
  }
  return current.state.steps;
}

